var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"말도 안 돼…….","JPN":"そんな……","ENG":"Impossible…","TWN":"怎麼可能……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"어떻게 용의 힘을 잃고도 이전보다 더 강해질 수 있는 거죠?","JPN":"龍の力を失ったはずなのに、なぜ以前よりも強くなれたのですか？","ENG":"How could you grow even stronger upon losing the power of the Dragon?","TWN":"怎麼可能失去龍的力量後，卻變得比以前更強？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"분명 당신은 이제 평범한 인간일 뿐인데……!","JPN":"あなたはもはや平凡な人間に過ぎないはず……！","ENG":"Surely, you're nothing but an ordinary human by now…!","TWN":"現在的你應該只是個平凡人才對……！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 반대로 생각해 보시면 어떤가요?","JPN":"ハハ、逆に考えてみてはいかがですか？","ENG":"Haha, have you ever considered it's the other way around?","TWN":"哈哈～你要不要逆向思考一下？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"인간이기에 이런 힘과 집념을 가질 수 있는 거라고.","JPN":"平凡な人間だからこそ、このような力と執念を持つことができるのです。","ENG":"Maybe I'm capable of such power and determination because I'm human.","TWN":"因為我是人，所以可以有這樣的力量和信念。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"시끄러워!","JPN":"うるさい！","ENG":"Silence!","TWN":"你閉嘴！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"고작 인간의 몸으로 이런 힘을 가질 수 있다면, 저와 동료들은 어째서 인간이기를 포기했어야 했던 겁니까?!","JPN":"たかが人間ごときの体でこんな力を持つことができるなら、どうして私と仲間たちは人間であることを諦めなければならなかったのですか？","ENG":"If it was possible to possess such powers as a mere human, why must my colleagues and I have forfeited our humanity?!","TWN":"若是區區血肉之軀可以有這樣的力量，我和伙伴們又何必要放棄做人？！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"저에게 그렇게 물어 보셔도 답을 드릴 수는 없겠네요.","JPN":"僕にそんなことを聞かれても答えることはできませんね。","ENG":"I'm afraid I can't answer that question for you.","TWN":"就算你問我我也無法回答你。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"당신의 삶의 방식은 복수이고, 복수란 괴물로 바뀌어 가는 과정이니까요.","JPN":"あなたの生き方は復讐であり、復讐とは化け物に堕ちていく過程ですから。","ENG":"All I can say is that your way of living was revenge, and revenge turns people into monsters.","TWN":"你的生存之道是報仇，但在報仇的過程中會把你變成一個怪物！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하지만 만약 당신들이 끝까지 인간으로 남으려고 했다면…….","JPN":"しかし、もしあなたたちが最後まで人間であろうとしたなら……","ENG":"If you guys decided to remain human until the very end…","TWN":"但如果你們堅持要以人類之姿活著……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"지금과는 다른 결과가 있었을지도 모르죠.","JPN":"今とは違う結果があったかもしれません。","ENG":"Perhaps there may have been different results.","TWN":"或許現在就不會是這樣的結果。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아니, 그런 일은 결단코 없었을 겁니다.","JPN":"いえ、そんなことは決してなかったはず。","ENG":"No. It would have never come to that.","TWN":"不，那種事絕對不會發生！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"당신과 마찬가지로, 저 역시 제 삶을 후회하지는 않으니까요.","JPN":"あなたと同じく、私も自分の人生を後悔していません。","ENG":"Because like you, I too have no regrets about my life.","TWN":"我和你一樣，我不會對我的決定而後悔！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그래서 어쨌다는 거야?","JPN":"だからそれがどうしたっていうの？","ENG":"So what?","TWN":"所以你現在想怎樣？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신 계획은 실패했어! 이대로 계속 싸운다고 뭐가 달라질 것 같아?!","JPN":"あんたの計画は失敗した！　このまま戦っても何も変わらない！","ENG":"Your plan failed! You think fighting us will change anything?","TWN":"你的計畫失敗了！就算再打下去結果也不會改變！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"…No.","TWN":"不……"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"계획은 틀어졌지만, 결국 변하는 것은 없습니다.","JPN":"計画は狂いましたが、結末が変わることはありません。","ENG":"You may have thwarted our initial plan, but this changes nothing.","TWN":"計畫出錯，但結果是一樣的！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자아, 늑대여. 어서 절 찌르고, 그 검에 제 피와 혼을 먹이십시오.","JPN":"さあ、狼よ。はやく私を刺して、その剣に私の血と魂を喰わせてください。","ENG":"Come now, Wolf. Stab me and feed your blade with my blood and soul.","TWN":"來吧！受詛咒的狼。快用那把劍刺進我的身體吸取我的血和靈魂！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};